-- 2026-07-08 一次性运维：清理 740 个孤儿听力音频
-- 背景：2026-07-07 题库去重删掉 860 条重复题（QUESTION-PIPELINE-REVIEW-2026-07-07 §2.2），
--       其配音文件留在 listening_audio 桶白占存储。本脚本删其中 740 个；
--       另外 120 个仍被练习历史(sessions)引用，为保历史回放【保留】。
-- 安全核对（已做）：与 live 题库 id/路径零交集；个人题库、错题收藏 0 引用。
-- 机制：临时启用 http 扩展，从数据库端调用已部署的 Edge Function cleanup-orphan-audio
--       （函数内用 service role 走 Storage API 正规删除，不留 S3 孤儿文件），跑完卸载扩展。
-- 用法：把下方 tok 里的占位符换成一次性 token（Claude 会话里单独提供），
--       整个文件粘进 Supabase Dashboard → SQL Editor → Run，约 10~60 秒。
-- 结果：SQL Editor 只显示最后一个查询的结果 = 四个文件夹剩余文件数，
--       应为：announcement 198 / choose-response 512 / conversation 211 / lecture 154
--       （若近期另有增删，数字可能略有出入）。
-- 跑完后：告诉 Claude「跑完了」，由其复核 + 函数换失效桩 + 台账登记。

create extension if not exists http with schema extensions;

-- 单批 200 个文件的删除可能超过 http 扩展默认 5 秒超时，放宽到 120 秒（仅本会话生效）
select extensions.http_set_curlopt('CURLOPT_TIMEOUT_MS', '120000');

with tok(t) as (
  select 'PASTE_ONE_OFF_TOKEN_HERE'
),
