select (r.resp).status as status, (r.resp).content as content
from batches b, tok
cross join lateral (
  select extensions.http_post(
    'https://ukoflmessliyvrvrddrd.supabase.co/functions/v1/cleanup-orphan-audio',
    '{"token":"' || tok.t || '","paths":' || b.paths || '}',
    'application/json'
  ) as resp
) r;

drop extension if exists http;

-- 验证：删除后各文件夹剩余文件数
select split_part(name,'/',1) as folder, count(*) as files
from storage.objects
where bucket_id='listening_audio'
  and split_part(name,'/',1) in ('choose-response','conversation','announcement','lecture')
group by 1 order by 1;
